#[test]
fn test_mutable_param_is_mutable_in_c() {
    // A @param should be declared as mutable in the generated C code
    let source = r#"
fn modify(@x: i32) i32 {
    x = x + 1;
    ret x;
}
fn main() {
    ret 0;
}
"#;
    let c = transpile_to_c(source);
    // The parameter x should be a mutable variable (no const)
    assert!(c.contains("modify"), "Should have modify function");
    // x should be declared and assigned to (mutable)
    assert!(c.contains("v_"), "Should have C variable references");
}

#[test]
fn test_immutable_param_is_immutable_in_c() {
    // A non-@param should be declared as immutable
    let source = r#"
fn compute(a: i32, b: i32) i32 {
    ret a + b;
}
fn main() {
    ret 0;
}
"#;
    let c = transpile_to_c(source);
    assert!(c.contains("compute"), "Should have compute function");
    // Parameters should appear in the function signature
    assert!(c.contains("v_"), "Should have C variable references");
}

